function gererNotes() {
  let notes = [];
  let somme = 0;

  // 1. Saisie des notes
  for (let i = 0; i < 5; i++) {
    let note = parseFloat(prompt("Entrez la note de l'élève " + (i+1)));
    notes.push(note);
  }

  document.write("<h2>Relevé des notes</h2>");

  // 2. Affichage des notes et calcul de la somme
  for (let i = 0; i < notes.length; i++) {
    document.write("Note de l'élève " + (i+1) + " : " + notes[i] + "<br>");
    somme = somme + notes[i];
  }

  // 3. Calcul de la moyenne
  let moyenne = somme / notes.length;

  document.write("<br>Somme des notes : " + somme + "<br>");
  document.write("Moyenne de la classe : " + moyenne + "<br><br>");

  // 4. Appréciation
  if (moyenne >= 14) {
    document.write("<strong>Appréciation : Excellent groupe !</strong>");
  } else if (moyenne >= 10) {
    document.write("<strong>Appréciation : Groupe moyen.</strong>");
  } else {
    document.write("<strong>Appréciation : Besoin de révision.</strong>");
  }
}
