function corrigerQCM() {
  const reponsesCorrectes = ['A', 'C', 'B'];
  let reponsesUtilisateur = [];
  let score = 0;

  // Saisie des réponses
  for (let i = 0; i < reponsesCorrectes.length; i++) {
    let reponse = prompt('Question ' + (i+1) + ' (Réponse A, B, C ou D) :');
    reponse = reponse.toUpperCase(); // Pour éviter les erreurs de casse
    reponsesUtilisateur.push(reponse);
  }

  // Affichage en-tête
  document.write("<h2>Résultats du QCM</h2>");
  document.write("<table border='1'>");
  document.write("<tr><th>Question</th><th>Votre réponse</th><th>Bonne réponse</th><th>Statut</th></tr>");

  // Comparaison et affichage
  for (let i = 0; i < reponsesCorrectes.length; i++) {
    let estCorrect = (reponsesUtilisateur[i] === reponsesCorrectes[i]);
    if (estCorrect) {
      score++;
      document.write("<tr><td>Q" + (i+1) + "</td><td>" + reponsesUtilisateur[i] + "</td><td>" + reponsesCorrectes[i] + "</td><td bgcolor='lightgreen'>Correct</td></tr>");
    } else {
      document.write("<tr><td>Q" + (i+1) + "</td><td>" + reponsesUtilisateur[i] + "</td><td>" + reponsesCorrectes[i] + "</td><td bgcolor='lightcoral'>Incorrect</td></tr>");
    }
  }
  document.write("</table><br>");

  // Mention
  document.write("<strong>Score : " + score + " / " + reponsesCorrectes.length + "</strong><br>");

  if (score === 3) {
    document.write("Mention : Excellent");
  } else if (score === 2) {
    document.write("Mention : Assez bien");
  } else if (score === 1) {
    document.write("Mention : Peu satisfaisant");
  } else {
    document.write("Mention : À réviser");
  }
}
